export function parseConfidentialBurnInstruction<TProgram extends string, TAccountMetas extends readonly AccountMeta[]>(
    instruction: Instruction<TProgram> &
        InstructionWithAccounts<TAccountMetas> &
        InstructionWithData<ReadonlyUint8Array>,
): ParsedConfidentialBurnInstruction<TProgram, TAccountMetas> {
    if (instruction.accounts.length < 3) {
        // TODO: Coded error.
        throw new Error('Not enough accounts');
    }
    let accountIndex = 0;
    const getNextAccount = () => {
        const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
        accountIndex += 1;
        return accountMeta;
    };
    let optionalAccountsRemaining = instruction.accounts.length - 3;
    const getNextOptionalAccount = () => {
        if (optionalAccountsRemaining === 0) return undefined;
        optionalAccountsRemaining -= 1;
        return getNextAccount();
    };
    return {
        programAddress: instruction.programAddress,
        accounts: {
            token: getNextAccount(),
            mint: getNextAccount(),
            instructionsSysvar: getNextOptionalAccount(),
            equalityRecord: getNextOptionalAccount(),
            ciphertextValidityRecord: getNextOptionalAccount(),
            rangeRecord: getNextOptionalAccount(),
            authority: getNextAccount(),
        },
        data: getConfidentialBurnInstructionDataDecoder().decode(instruction.data),
    };
}
